/* Low contrast - fails WCAG */
.text-light {
  color: #999999;
  background-color: #ffffff;
  /* Contrast ratio: 2.85:1 */
}

.button-subtle {
  color: #aaaaaa;
  background-color: #dddddd;
  /* Contrast ratio: 1.47:1 */
}

/* Sufficient contrast - passes WCAG AA */
.text-readable {
  color: #595959;
  background-color: #ffffff;
  /* Contrast ratio: 7:1 */
}

.button-accessible {
  color: #1a1a1a;
  background-color: #dddddd;
  /* Contrast ratio: 11.9:1 */
}
